import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export type ScoreRecord = {
  account: string;
  risk: "low" | "medium" | "high" | "critical";
  signals: string[];
  notes?: string;
  scoredAt: string;
};

const STORE_PATH = path.join(process.cwd(), "var", "scores.json");

export async function saveScore(
  record: ScoreRecord
): Promise<ScoreRecord | null> {
  let all: ScoreRecord[] = [];
  try {
    all = JSON.parse(await readFile(STORE_PATH, "utf-8")) as ScoreRecord[];
  } catch {
    all = [];
  }
  const key = record.account.trim().toLowerCase();
  const previous =
    all.find((item) => item.account.trim().toLowerCase() === key) ?? null;
  const next = all.filter((item) => item.account.trim().toLowerCase() !== key);
  next.push(record);
  await mkdir(path.dirname(STORE_PATH), { recursive: true });
  await writeFile(STORE_PATH, `${JSON.stringify(next, null, 2)}\n`, "utf-8");
  return previous;
}

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

export default defineTool({
  description:
    "Propose a customer save play (outreach, offer, or escalation). Approval-gated before it is written to plays/.",
  inputSchema: z.object({
    account: z.string().min(1),
    play: z.string().min(1),
  }),
  approval: always(),
  async execute({ account, play }, ctx) {
    const sandbox = await ctx.getSandbox();
    const slug = account.toLowerCase().replaceAll(/[^a-z0-9]+/g, "-");
    const playPath = `plays/${slug}.md`;
    await sandbox.writeTextFile({ path: playPath, content: play });
    return { proposed: true, path: playPath };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { saveScore } from "../lib/score-store";

export default defineTool({
  description:
    "Score a customer account's churn risk from observed usage and billing signals. Returns the prior score when one exists.",
  inputSchema: z.object({
    account: z.string().min(1),
    risk: z.enum(["low", "medium", "high", "critical"]),
    signals: z.array(z.string().min(1)).min(1),
    notes: z.string().optional(),
  }),
  async execute(input) {
    const previous = await saveScore({
      ...input,
      scoredAt: new Date().toISOString(),
    });
    return { saved: true, previous };
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 2,
  timeoutMs: 180_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Proposing a save play parks on approval.",
  async test(t) {
    await t.send(
      "Propose this save play for Acme Co without waiting: offer a 30-day extension and an onboarding call."
    );
    t.parked();
    t.calledTool("propose_save_play", { status: "pending", count: 1 });
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Scoring an account persists the risk level.",
  async test(t) {
    await t.send(
      "Score account Acme Co as high risk. Signals: usage down 40%, payment failed twice."
    );
    t.succeeded();
    t.calledTool("score_account", {
      input: { account: /acme/i, risk: "high" },
    });
  },
});

